alter table public.profiles add column if not exists deletion_requested_at timestamptz;
create table if not exists public.data_export_requests (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.profiles(id) on delete cascade, status text not null default 'requested' check(status in ('requested','processing','ready','failed')), requested_at timestamptz not null default now(), completed_at timestamptz);
create table if not exists public.account_deletion_requests (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.profiles(id) on delete restrict, status text not null default 'requested' check(status in ('requested','reviewing','canceled','completed')), requested_at timestamptz not null default now(), canceled_at timestamptz, completed_at timestamptz);
alter table public.data_export_requests enable row level security; alter table public.account_deletion_requests enable row level security;
grant select,insert on public.data_export_requests to authenticated; grant select,insert,update on public.account_deletion_requests to authenticated;
create policy "data_export_own_select" on public.data_export_requests for select to authenticated using(user_id=auth.uid()); create policy "data_export_own_insert" on public.data_export_requests for insert to authenticated with check(user_id=auth.uid());
create policy "deletion_request_own_select" on public.account_deletion_requests for select to authenticated using(user_id=auth.uid()); create policy "deletion_request_own_insert" on public.account_deletion_requests for insert to authenticated with check(user_id=auth.uid() and not exists(select 1 from public.communities community where community.owner_id=auth.uid())); create policy "deletion_request_own_cancel" on public.account_deletion_requests for update to authenticated using(user_id=auth.uid() and status='requested') with check(user_id=auth.uid() and status='canceled');
-- Export generation and final deletion are trusted background/operator workflows. No renderer route can hard-delete an account.
